import React, { useState, useEffect } from 'react';
import './SplashScreen.css';

const SplashScreen = ({ onComplete }) => {
  const [phase, setPhase] = useState('fadeIn'); // fadeIn, scale, pulse, fadeOut

  useEffect(() => {
    const timeline = setTimeout(() => {
      setPhase('scale');
    }, 800);

    const scaleTimeline = setTimeout(() => {
      setPhase('pulse');
    }, 1500);

    const pulseTimeline = setTimeout(() => {
      setPhase('fadeOut');
    }, 2500);

    const completeTimeline = setTimeout(() => {
      onComplete();
    }, 3200);

    return () => {
      clearTimeout(timeline);
      clearTimeout(scaleTimeline);
      clearTimeout(pulseTimeline);
      clearTimeout(completeTimeline);
    };
  }, [onComplete]);

  return (
    <div className={`splash-screen ${phase}`}>
      <div className="splash-content">
        <div className="logo-container">
          <img 
            src="/assets/portiq-logo.png" 
            alt="PortIQ Technologies" 
            className="splash-logo"
            onError={(e) => {
              // Fallback if logo doesn't exist
              e.target.style.display = 'none';
              e.target.nextSibling.style.display = 'block';
            }}
          />
          <div className="logo-text-fallback" style={{ display: 'none' }}>
            <div className="portiq-text">PortIQ</div>
            <div className="technologies-text">Technologies</div>
          </div>
        </div>
        <div className="splash-subtitle">Visitor Management System</div>
        <div className="loading-dots">
          <span></span>
          <span></span>
          <span></span>
        </div>
      </div>
    </div>
  );
};

export default SplashScreen;
